        best = None
        best_key = None
        for x, y in resources:
            ds = cheb(sx, sy, x, y)
            do = cheb(ox, oy, x, y)
            key = (do <= ds, ds, -do, x, y)  # prefer resource we can reach first (or tie), then closest, then deterministic
            if best_key is None or key > best_key:
                best_key = key
                best = (x, y)
